import express, { type Request, type Response, type NextFunction } from "express";
import { type } from "arktype";

// ─── Schemas ───────────────────────────────────────────────────────────────

const userBodySchema = type({
  username: "string.alphanumeric & string >= 3 & string <= 20",
  email: "string.email",
  "age?": "integer >= 13 <= 120",
});

const searchQuerySchema = type({
  q: "string >= 1 <= 100",
  page: "string |> number & integer >= 1",
  limit: "string |> number & integer >= 1 <= 50",
});

// ─── Middleware factory ────────────────────────────────────────────────────

function validate(source: "body" | "query") {
  return async (req: Request, res: Response, next: NextFunction) => {
    // The schema is passed via a closure or we attach it differently.
    // We'll use a pattern where the schema is stored on a property.
    // Actually, let's use a cleaner approach: validate returns a function
    // that takes the schema as well. We'll use a two-step factory.
    next(); // placeholder — see below
  };
}

// We need the middleware to receive the schema. Let's use a curried approach:
// validate(source, schema) returns the middleware.

function createValidate(source: "body" | "query", schema: { "~standard": { validate: (value: unknown) => any } }) {
  return async (req: Request, res: Response, next: NextFunction) => {
    const result = await schema["~standard"].validate(req[source]);

    if (result.issues) {
      res.status(400).json({ issues: result.issues });
      return;
    }

    req[source] = result.value;
    next();
  };
}

// ─── App ───────────────────────────────────────────────────────────────────

const app = express();

app.use(express.json());

app.post("/users", createValidate("body", userBodySchema), (req: Request, res: Response) => {
  res.status(201).json(req.body);
});

app.get("/search", createValidate("query", searchQuerySchema), (req: Request, res: Response) => {
  res.json(req.query);
});

app.listen(3000, () => {
  console.log("Server listening on port 3000");
});

